interface RecipeDef {
  id: string
  name: string
  hint: string
  match: (items: Item[]) => boolean
  build: (items: Item[], rng: Rng) => Item
}

// 3x same rune → next rune
{
  id: 'rune_upgrade',
  name: 'Rune Upgrade',
  hint: '3 of the same rune',
  match: (items) => items.length === 3 && items.every(i => i.baseId === items[0].baseId && i.slot === 'rune'),
  build: (items, rng) => generateRune(RUNE_LADDER[items[0].baseId])
}

const [slots, setSlots] = useState<(Item | null)[]>([null, null, null, null])
const result = useMemo(() => {
  const filled = slots.filter(Boolean) as Item[]
  if (filled.length === 0) return null
  return transmute(filled, makeRng(Date.now()))
}, [slots])
